-- Master Inventory Seed Data
-- Generated from Walmart + HEB + Amazon purchase history
-- Family of 8, Boerne TX, April 2026

-- Create inventory tables if not exist

CREATE TABLE IF NOT EXISTS inventory_items (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  canonical_name TEXT NOT NULL,
  category TEXT NOT NULL,        -- App category: Fridge, Freezer, Pantry, etc.
  sub_category TEXT NOT NULL,    -- Sub-category within the main category
  preferred_store TEXT,          -- Walmart, HEB, or Amazon
  available_stores TEXT[],       -- Array of stores that carry this item
  par_level INT DEFAULT 1,       -- How many to keep on hand
  par_unit TEXT DEFAULT 'item',  -- Unit for par level
  reorder_threshold INT DEFAULT 0, -- Reorder when stock drops to this
  current_stock INT DEFAULT 0,   -- Current quantity on hand
  location TEXT,                 -- Where stored: main_fridge, deep_freezer, pantry_shelf_1, etc.
  last_purchased TIMESTAMPTZ,
  avg_price DECIMAL(8,2),
  notes TEXT,
  active BOOLEAN DEFAULT TRUE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_inventory_category ON inventory_items(category);
CREATE INDEX IF NOT EXISTS idx_inventory_sub_category ON inventory_items(sub_category);
CREATE INDEX IF NOT EXISTS idx_inventory_name ON inventory_items(canonical_name);


